303→  portrait: string;
304→  /** このクラスタを代表するツイート（最大10件）。人物らしさが特に強く出ているものを選定 */
305→  representativeTweets: TaggedTweet[];
306→  /** このモードでよく取る態度パターン */
307→  attitudePatterns: AttitudePattern[];
