312→  name: string;
313→  /** パターンの説明 */
314→  description: string;
315→  /** このパターンが現れている実際のツイートID */
316→  exampleTweetIds: TweetId[];
317→  /** このパターンが出現するカテゴリ群（B-12対応） */
318→  sourceCategories: Category[];
319→}
320→```
