```

#### GeneratedText / EvaluationResult

```typescript
interface GeneratedText {
  text: string;
  topic: string;
  evaluation: EvaluationResult | null; // 評価済みの場合
  fewShotIds: TweetId[];
  modelUsed: ModelIdString;
}

interface EvaluationResult {
  /** 「同一人物が書いたように読めるか」の総合スコア (0.0-10.0) */
