import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { ModelIdString } from "@groa/types";
import type { ResolvedStepConfig } from "@groa/config";
import { ApiBackend, maskApiKey } from "./api-backend.js";
import type { LlmRequest } from "./types.js";

function createConfig(
  overrides: Partial<ResolvedStepConfig> = {},
): ResolvedStepConfig {
  return {
    backend: "api",
    apiKey: "sk-test-key-12345678",
    model: ModelIdString("claude-sonnet-4-6-20250227"),
    params: {},
    ...overrides,
  };
}

function createRequest(
  overrides: Partial<LlmRequest> = {},
): LlmRequest {
  return {
    model: "sonnet",
    messages: [
      { role: "system", content: "You are a helpful assistant." },
      { role: "user", content: "Hello" },
    ],
    maxTokens: 1024,
    options: { temperature: 0.0, useCache: false, useBatch: false },
    ...overrides,
  };
}

function mockFetchResponse(
  body: Record<string, unknown>,
  status = 200,
  headers: Record<string, string> = {},
) {
  return vi.fn().mockResolvedValue({
    ok: status >= 200 && status < 300,
    status,
    headers: new Headers(headers),
    json: () => Promise.resolve(body),
    text: () => Promise.resolve(JSON.stringify(body)),
  });
}

describe("maskApiKey", () => {
  it("先頭6文字以外をマスクする", () => {
    expect(maskApiKey("sk-ant-api03-xxxxx")).toBe(
      "sk-ant" + "*".repeat(17 - 6),
    );
  });

  it("6文字以下の短いキーは全マスク", () => {
    expect(maskApiKey("short")).toBe("***");
  });
});

describe("ApiBackend", () => {
  let originalFetch: typeof globalThis.fetch;

  beforeEach(() => {
    originalFetch = globalThis.fetch;
  });

  afterEach(() => {
    globalThis.fetch = originalFetch;
  });

